/**
 * @param {bigint} l
 * @param {bigint} r
 * @param {string} directions
 * @returns {number}
 */
function solve(l, r, directions) {
    let goodCount = 0n;

    // Helper function to check if a number is "good"
    const isGood = (xBigInt, directions) => {
        const xStr = xBigInt.toString().padStart(16, '0');

        // 1. Fill 4x4 grid
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));
        let k = 0;
        for (let i = 0; i < 4; i++) {
            for (let j = 0; j < 4; j++) {
                // The digits are characters '0'-'9', convert to integer
                grid[i][j] = parseInt(xStr[k++]);
            }
        }

        // 2. Simulate path traversal
        let row = 0;
        let col = 0;
        const path = [];

        // Record the starting element
        path.push(grid[row][col]);

        // Apply 6 directions
        for (let i = 0; i < 6; i++) {
            const move = directions[i];
            if (move === 'D') {
                row += 1;
            } else if (move === 'R') {
                col += 1;
            }

            // Boundary checks (although problem constraints imply valid moves for the 6 steps)
            if (row >= 4 || col >= 4) {
                // Should not happen based on typical contest setup, but good practice.
                break; 
            }

            // Record the element at the new position
            path.push(grid[row][col]);
        }

        // The resulting sequence should have length 7 (1 start + 6 moves)
        if (path.length !== 7) {
            // This should theoretically not happen if directions.length is 6
            return false;
        }

        // 3. Check for non-decreasing sequence
        for (let i = 0; i < 6; i++) {
            if (path[i] > path[i+1]) {
                return false; // Not non-decreasing
            }
        }

        return true; // Non-decreasing
    };

    // Iterate from l to r
    let current = l;
    while (current <= r) {
        if (isGood(current, directions)) {
            goodCount += 1n;
        }
        current += 1n;
    }

    // Return the count as a standard number if it fits, or handle big integer if needed.
    // Since r <= 9 * 10^15, the count will fit within standard JS number (up to 2^53 - 1).
    return Number(goodCount);
}

