fn solve(l: i64, r: i64, directions: String) -> i64 {
    let mut good_count = 0;

    for x in l..=r {
        let x_str = format!("{:016}", x);

        // 1. Fill 4x4 grid
        let mut grid = [[0; 4]; 4];
        let mut k = 0;
        for i in 0..4 {
            for j in 0..4 {
                // The digits are characters '0'-'9', convert to integer
                grid[i][j] = x_str.chars().nth(k).unwrap().to_digit(10).unwrap() as i32;
                k += 1;
            }
        }

        // 2. Simulate path traversal
        let mut row = 0;
        let mut col = 0;
        let mut path: Vec<i32> = Vec::with_capacity(7);

        // Record the starting element
        path.push(grid[row][col]);

        // Apply 6 directions
        for move_char in directions.chars() {
            if move_char == 'D' {
                row += 1;
            } else if move_char == 'R' {
                col += 1;
            }

            // Boundary checks are implicitly handled by the problem constraints ensuring 7 steps are valid
            // for the structure, but we check defensively.
            if row >= 4 || col >= 4 {
                // If this happens, the logic is flawed or input violates assumptions.
                // Since the path must be length 7, we break early if out of bounds.
                break;
            }

            // Record the element at the new position
            path.push(grid[row][col]);
        }

        // The resulting sequence must have length 7
        if path.len() != 7 {
            continue;
        }

        // 3. Check for non-decreasing sequence
        let mut is_non_decreasing = true;
        for i in 0..6 {
            if path[i] > path[i + 1] {
                is_non_decreasing = false;
                break;
            }
        }

        if is_non_decreasing {
            good_count += 1;
        }
    }

    good_count
}
